     9→  HttpException,
    10→  UseGuards,
    11→  UsePipes,
    12→  ValidationPipe,
    13→  UseInterceptors,
    14→} from '@nestjs/common';
    15→import {
    16→  ApiTags,
    17→  ApiOperation,
    18→  ApiResponse,
    19→  ApiParam,
    20→  ApiBearerAuth
    21→} from '@nestjs/swagger';
    22→import { TriggerEnrichmentDto } from './trigger-enrichment.dto';
    23→import { EnrichmentResponseDto } from './enrichment-response.dto';
    24→import { ErrorResponseDto } from '../shared/error-response.dto';
    25→import { JwtAuthGuard } from '../auth';
    26→import { AuthenticatedRequest } from '../auth/interfaces/authenticated-request.interface';
    27→import { Logger } from '@nestjs/common';
    28→import { ConfigService } from '../config/config.service';
    29→import { EnrichmentType } from '../shared/enrichment-types.enum';
    30→import { LoggingStorage } from '@app/logging/logging.cls';
    31→import { Transactional, AuditId, AuditingInterceptor, AsyncTransactionHelper, AuditingService } from '@app/auditing';
    32→import { EmbeddingQueueService } from '../enrichments-embeddings/embedding-queue.service';
    33→import { GlossaryQueueService } from '../enrichments-glossary/glossary-queue.service';
    34→import { DateExtractionQueueService } from '../enrichments-date-extraction/date-extraction-queue.service';
    35→import { TransactionType } from '@app/enrichment-server';
    36→
    37→@ApiTags('Enrichments')
    38→@Controller('enrichments')
    39→@UseInterceptors(AuditingInterceptor)
    40→export class EnrichmentApiController {
    41→  private readonly logger = new Logger(EnrichmentApiController.name);
    42→
    43→  constructor(
    44→    private readonly auditingService: AuditingService,
    45→    private readonly configService: ConfigService,
    46→    private readonly loggingStorage: LoggingStorage,
    47→    private readonly embeddingQueueService: EmbeddingQueueService,
    48→    private readonly glossaryQueueService: GlossaryQueueService,
    49→    private readonly dateExtractionQueueService: DateExtractionQueueService,
    50→    private readonly asyncHelper: AsyncTransactionHelper,
    51→  ) { }
    52→
    53→  @Post('trigger')
    54→  @UseGuards(JwtAuthGuard)
    55→  @UsePipes(new ValidationPipe({ transform: true, whitelist: true }))
    56→  @Transactional('enrichment-trigger', true)
    57→  @ApiOperation({ summary: 'Trigger a new enrichment job (manual only)' })
    58→  @ApiResponse({
    59→    status: 201,
    60→    description: 'Job created successfully',
    61→    type: EnrichmentResponseDto
    62→  })
    63→  @ApiResponse({
    64→    status: 400,
    65→    description: 'Invalid input',
    66→    type: ErrorResponseDto
    67→  })
    68→  @ApiResponse({
    69→    status: 401,
    70→    description: 'Unauthorized',
    71→    type: ErrorResponseDto
    72→  })
    73→  @ApiResponse({
    74→    status: 403,
    75→    description: 'Auto-enrichment disabled - manual trigger required',
    76→    type: ErrorResponseDto
    77→  })
    78→  @ApiResponse({
    79→    status: 429,
    80→    description: 'Too many requests',
    81→    type: ErrorResponseDto
    82→  })
    83→  @ApiBearerAuth()
    84→  async triggerEnrichment(
    85→    @Body() dto: TriggerEnrichmentDto,
    86→    @Request() req: AuthenticatedRequest,
    87→    @AuditId() auditId: string
    88→  ) {
    89→    try {
    90→      // Extract data from DTO
    91→      const { documentSourceId, types, priority, requestData, callbackUrl } = dto;
    92→
    93→      // Log the enrichment request
    94→      this.logger.log(
    95→        `User ${req.user.username} (ID: ${req.user.sub}) triggering enrichment for document ${documentSourceId} ` +
    96→        `with types: ${types.join(', ')} using transaction: ${auditId}`
    97→      );
    98→
    99→      // Use AsyncTransactionHelper for clean async execution
   100→      return this.asyncHelper.executeAsync(auditId, async () => {
   101→        const completedEnrichments: any[] = [];
   102→        const failedEnrichments: any[] = [];
   103→
   104→        // Process each enrichment type - services will create their own milestones  
   105→        for (const type of types) {
   106→          this.logger.log(`Processing enrichment type: ${type} for document: ${documentSourceId}`);
   107→
   108→          try {
   109→            // Call appropriate enrichment service - they handle their own milestones
   110→            let result: any;
   111→            switch (type) {
   112→              case TransactionType.EMBEDDING:
   113→                this.logger.log(`Calling embedding service for document: ${documentSourceId}`);
   114→                result = await this.embeddingQueueService.addEmbeddingJob(
   115→                  documentSourceId,
   116→                  requestData?.batchSize,
   117→                  undefined, // neo4jCredentials - no longer needed
   118→                  undefined, // auditId - service will create its own milestone
   119→                  false, // isRetry
   120→                  requestData
   121→                );
   122→                break;
   123→
   124→              case TransactionType.GLOSSARY_ADD:
   125→                this.logger.log(`Calling glossary service for document: ${documentSourceId}`);
   126→                result = await this.glossaryQueueService.addGlossaryJob(
   127→                  documentSourceId,
   128→                  'GLOSSARY_ADD',
   129→                  undefined, // neo4jCredentials - no longer needed
   130→                  undefined, // auditId - service will create its own milestone
   131→                  false, // isRetry
   132→                  requestData
   133→                );
   134→                break;
   135→
   136→              case TransactionType.DATE_EXTRACTION:
   137→                this.logger.log(`Calling date extraction service for document: ${documentSourceId}`);
   138→                result = await this.dateExtractionQueueService.addDateExtractionJob(
   139→                  documentSourceId,
   140→                  undefined, // neo4jCredentials - no longer needed
   141→                  undefined, // auditId - service will create its own milestone
   142→                  false, // isRetry
   143→                  requestData,
   144→                  requestData?.options
   145→                );
   146→                break;
   147→
   148→              default:
   149→                throw new HttpException(
   150→                  `Unsupported enrichment type: ${type}`,
   151→                  HttpStatus.BAD_REQUEST
   152→                );
   153→            }
   154→
   155→            completedEnrichments.push({
   156→              type,
   157→              status: 'COMPLETED',
   158→              result
   159→            });
   160→
   161→            this.logger.log(`Successfully completed ${type} enrichment for document: ${documentSourceId}`);
   162→
   163→          } catch (error: any) {
   164→            failedEnrichments.push({
   165→              type,
   166→              status: 'FAILED',
   167→              error: error.message
   168→            });
   169→
   170→            this.logger.error(`Failed ${type} enrichment for document ${documentSourceId}: ${error.message}`, error.stack);
   171→          }
   172→        }
   173→
   174→        // Return response - the @Transactional wrapper will handle audit completion
   175→        const successfulCount = completedEnrichments.length;
   176→        const totalCount = types.length;
   177→        
   178→        return {
   179→          auditId, // Using REQUEST audit ID for backwards compatibility
   180→          status: successfulCount === totalCount ? 'COMPLETED' :
   181→            successfulCount > 0 ? 'PARTIAL_SUCCESS' : 'FAILED',
   182→          documentSourceId: documentSourceId,
   183→          createdAt: new Date(),
   184→          message: `${successfulCount}/${totalCount} enrichment(s) completed successfully`,
   185→          results: [...completedEnrichments, ...failedEnrichments]
   186→        } as EnrichmentResponseDto;
   187→      });
   188→
   189→    } catch (error: any) {
   190→      this.logger.error(`Error triggering enrichment job: ${error.message}`, error.stack || '');
   191→      throw new HttpException(
   192→        error.message || 'Failed to trigger enrichment job',
   193→        error.status || HttpStatus.INTERNAL_SERVER_ERROR
   194→      );
   195→    }
   196→  }
   197→
   198→  @Get('status/:auditId')
   199→  @UseGuards(JwtAuthGuard)
   200→  @ApiOperation({ summary: 'Get enrichment audit status (updated from transaction compatibility)' })
   201→  @ApiParam({ name: 'auditId', description: 'Audit ID to check (replaces transaction ID)' })
   202→  @ApiResponse({
   203→    status: 200,
   204→    description: 'Audit status retrieved successfully'
   205→  })
   206→  @ApiResponse({
   207→    status: 404,
   208→    description: 'Audit not found',
   209→    type: ErrorResponseDto
   210→  })
   211→  @ApiBearerAuth()
   212→  async getEnrichmentStatus(
   213→    @Param('auditId') auditId: string,
   214→    @Request() req: AuthenticatedRequest
   215→  ) {
   216→    try {
   217→      // Get the audit trace using the shared auditing service
   218→      const trace = await this.auditingService.getFullTrace(auditId);
   219→
   220→      if (!trace.request) {
   221→        throw new HttpException('Audit not found', HttpStatus.NOT_FOUND);
   222→      }
   223→
   224→      // Return audit status in format compatible with DS expectations
   225→      return {
   226→        auditId: trace.request.id,
   227→        status: trace.request.status,
   228→        category: trace.request.category,
   229→        createdAt: trace.request.started || trace.request.created_at,
   230→        updatedAt: trace.request.completed || trace.request.updated_at,
   231→        duration: trace.request.duration,
   232→        error: trace.request.error,
   233→        milestones: trace.milestones.map(m => ({
   234→          id: m.id,
   235→          category: m.category,
   236→          status: m.status,
   237→          metadata: m.metadata,
   238→          duration: m.duration,
   239→          error: m.error
   240→        }))
   241→      };
   242→    } catch (error: any) {
   243→      this.logger.error(`Error getting enrichment status: ${error.message}`, error.stack || '');
   244→      throw new HttpException(
   245→        error.message || 'Failed to get enrichment status',
   246→        error.status || HttpStatus.INTERNAL_SERVER_ERROR
   247→      );
   248→    }
   249→  }
   250→
   251→  @Get('types')
   252→  @UseGuards(JwtAuthGuard)
   253→  @ApiOperation({ summary: 'Get all available enrichment types' })
   254→  @ApiResponse({
   255→    status: 200,
   256→    description: 'Available enrichment types retrieved successfully'
   257→  })
   258→  @ApiResponse({
   259→    status: 401,
   260→    description: 'Unauthorized',
   261→    type: ErrorResponseDto
   262→  })
   263→  @ApiBearerAuth()
   264→  async getAvailableEnrichmentTypes(@Request() req: AuthenticatedRequest) {
   265→    try {
   266→      this.logger.log(`User ${req.user.username} (ID: ${req.user.sub}) requesting available enrichment types`);
   267→
   268→      const enrichments = [
   269→        {
   270→          id: 'embedding',
   271→          name: 'Vector Embeddings',
   272→          description: 'Generate vector embeddings for semantic search',
   273→          enabled: true,
   274→          isRegistered: true,
   275→          type: EnrichmentType.EMBEDDING
   276→        },
   277→        {
   278→          id: 'glossary',
   279→          name: 'Glossary Linking',
   280→          description: 'Link and manage glossary terms in documents',
   281→          enabled: true,
   282→          isRegistered: true,
   283→          type: EnrichmentType.GLOSSARY_LINKING
   284→        },
   285→        {
   286→          id: 'date_extraction',
   287→          name: 'Date Extraction',
   288→          description: 'Extract and structure dates from document text',
   289→          enabled: true,
   290→          isRegistered: true,
   291→          type: EnrichmentType.DATE_EXTRACTION
   292→        }
   293→      ];
   294→
   295→      return {
   296→        enrichments
   297→      };
   298→    } catch (error: any) {
   299→      this.logger.error(`Error getting available enrichment types: ${error.message}`, error.stack || '');
   300→      throw new HttpException(
   301→        error.message || 'Failed to get available enrichment types',
   302→        error.status || HttpStatus.INTERNAL_SERVER_ERROR
   303→      );
   304→    }
   305→  }
   306→}
