     1→import { OnModuleDestroy, OnModuleInit } from '@nestjs/common';
     2→import { Queue, Worker, QueueEvents, JobsOptions } from 'bullmq';
     3→import { RedisConnectionService } from './redis-connection.service';
     4→import { LoggingStorage } from '@app/logging';
     5→import { Logger } from '@nestjs/common';
     6→import { ClsService } from 'nestjs-cls';
     7→
     8→export interface BaseJobData {
     9→    documentSourceId: string;
    10→    neo4jCredentials?: Record<string, unknown>;
    11→    transactionId?: string;
    12→    isRetry?: boolean;
    13→    requestData?: Record<string, unknown>;
    14→    traceId?: string;
    15→}
    16→
    17→export interface BaseJobResult {
    18→    documentSourceId: string;
    19→    success: boolean;
    20→    processingTimeMs: number;
    21→}
    22→
    23→export abstract class BaseQueueService<
    24→    TJobData extends BaseJobData,
    25→    TJobResult extends BaseJobResult
    26→> implements OnModuleInit, OnModuleDestroy {
    27→    protected queue: Queue;
    28→    protected worker: Worker;
    29→    protected queueEvents: QueueEvents;
    30→    protected readonly logger: Logger = new Logger(BaseQueueService.name);
    31→
    32→    // Shared configuration constants
    33→    protected readonly RETRY_ATTEMPTS = 3;
    34→    protected readonly JOB_TIMEOUT_MS = 30 * 60 * 1000; // 30 minutes
    35→    protected readonly BACKOFF_DELAY_MS = 2000;
    36→    protected readonly QUEUE_CLEAN_LIMIT = 1000;
    37→
    38→    // Abstract properties - each service must define these
    39→    protected abstract readonly queueName: string;
    40→    protected abstract readonly jobName: string;
    41→    protected abstract readonly defaultRedisDb: string;
    42→
    43→    constructor(
    44→        protected readonly redisConnection: RedisConnectionService,
    45→        protected readonly loggingStorage: LoggingStorage,
    46→    ) { }
    47→
    48→    // Abstract method - each service implements its own job processing logic
    49→    protected abstract processJob(data: TJobData): Promise<TJobResult>;
    50→
    51→    async onModuleInit() {
    52→        // Get database number from environment variable or use default
    53→        const db = parseInt(this.getRedisDbEnvVar() || this.defaultRedisDb);
    54→
    55→        // Use cached Redis connection from connection service
    56→        const sharedConnection = this.redisConnection.getConnection(db);
    57→
    58→        // Create queue using shared connection
    59→        this.queue = new Queue(this.queueName, {
    60→            connection: sharedConnection,
    61→        });
    62→
    63→        // Create QueueEvents using the same shared connection
    64→        this.queueEvents = new QueueEvents(this.queueName, {
    65→            connection: sharedConnection,
    66→        });
    67→
    68→        // Create single-threaded worker using the same shared connection
    69→        this.worker = new Worker(this.queueName,
    70→            async (job) => {
    71→
    72→                this.logger.log(`Processing ${this.queueName} job: ${job.id} for document: ${job.data.documentSourceId}`);
    73→                const traceId = job.data.traceId ?? 'lost-trace-id';
    74→
    75→                return this.loggingStorage.wrap(async () => {
    76→                    // Now set your traceId
    77→                    this.loggingStorage.setTraceId(traceId);
    78→                    this.logger.verbose(`Process job off queue ${JSON.stringify(job.data)}`);
    79→
    80→                    // Process the job
    81→                    return this.processJob(job.data);
    82→                });
    83→
    84→            },
    85→            {
    86→                connection: sharedConnection,
    87→            }
    88→        );
    89→
    90→        this.worker.on('completed', async (job, result: TJobResult) => {
    91→            this.logger.log(`${this.queueName} job completed for document ${result.documentSourceId}`);
    92→        });
    93→
    94→        this.worker.on('failed', async (job, error) => {
    95→            if (job?.id) {
    96→                this.logger.error(`${this.queueName} job failed for job ${job.id}:`, error);
    97→            } else {
    98→                this.logger.error(`${this.queueName} job failed (no job ID available):`, error);
    99→            }
   100→        });
   101→
   102→        this.logger.log(`${this.queueName} queue and worker initialized`);
   103→    }
   104→
   105→    // Abstract method for getting the Redis DB environment variable name
   106→    protected abstract getRedisDbEnvVar(): string | undefined;
   107→
   108→    // Common job creation method
   109→    protected async createJob(
   110→        jobData: TJobData,
   111→        options: Partial<JobsOptions> = {}
   112→    ): Promise<string> {
   113→        // Input validation
   114→        if (!jobData.documentSourceId || typeof jobData.documentSourceId !== 'string') {
   115→            throw new Error('documentSourceId is required and must be a string');
   116→        }
   117→
   118→        // Automatically get trace ID from CLS context
   119→        const traceId = this.loggingStorage.getTraceId();
   120→        const finalJobData = { ...jobData, traceId };
   121→
   122→        const defaultOptions: JobsOptions = {
   123→            priority: 1,
   124→            attempts: this.RETRY_ATTEMPTS,
   125→            backoff: {
   126→                type: 'exponential',
   127→                delay: this.BACKOFF_DELAY_MS,
   128→            },
   129→        };
   130→
   131→        const job = await this.queue.add(this.jobName, finalJobData, {
   132→            ...defaultOptions,
   133→            ...options,
   134→        });
   135→
   136→        if (!job.id) {
   137→            throw new Error('Failed to create job - no ID returned');
   138→        }
   139→
   140→        this.logger.log(`📋 Queued ${this.queueName} job ${job.id} for document ${jobData.documentSourceId}`);
   141→        return job.id;
   142→    }
   143→
   144→    // Common method to wait for job completion
   145→    protected async waitForJobCompletion(jobId: string): Promise<TJobResult> {
   146→        // Ensure the service is initialized
   147→        if (!this.queue || !this.worker) {
   148→            this.logger.log(`🔧 ${this.queueName} not initialized, calling onModuleInit...`);
   149→            await this.onModuleInit();
   150→        }
   151→
   152→        this.logger.log(`📋 Job ${jobId} queued, waiting for completion...`);
   153→
   154→        // Wait for the job to complete
   155→        const job = await this.queue.getJob(jobId);
   156→        if (!job) {
   157→            throw new Error(`Job ${jobId} not found`);
   158→        }
   159→
   160→        // Wait for completion with timeout
   161→        const result = await job.waitUntilFinished(this.queueEvents, this.JOB_TIMEOUT_MS);
   162→
   163→        this.logger.log(`${this.queueName} job ${jobId} completed`);
   164→        return result as TJobResult;
   165→    }
   166→
   167→    // Shared utility methods
   168→    async getQueueStatus() {
   169→        const waiting = await this.queue.getWaiting();
   170→        const active = await this.queue.getActive();
   171→        const completed = await this.queue.getCompleted();
   172→        const failed = await this.queue.getFailed();
   173→
   174→        return {
   175→            waiting: waiting.length,
   176→            active: active.length,
   177→            completed: completed.length,
   178→            failed: failed.length,
   179→            workerThreads: 1, // Single-threaded
   180→        };
   181→    }
   182→
   183→    async getJobDetails(jobId: string) {
   184→        // Input validation
   185→        if (!jobId || typeof jobId !== 'string') {
   186→            throw new Error('jobId is required and must be a string');
   187→        }
   188→
   189→        const job = await this.queue.getJob(jobId);
   190→        if (!job) {
   191→            throw new Error(`Job ${jobId} not found`);
   192→        }
   193→
   194→        return {
   195→            id: job.id,
   196→            name: job.name,
   197→            data: job.data,
   198→            progress: job.progress,
   199→            returnvalue: job.returnvalue,
   200→            failedReason: job.failedReason,
   201→            processedOn: job.processedOn,
   202→            finishedOn: job.finishedOn,
   203→            timestamp: job.timestamp,
   204→            attemptsMade: job.attemptsMade,
   205→            opts: job.opts
   206→        };
   207→    }
   208→
   209→    async cancelJob(jobId: string) {
   210→        // Input validation
   211→        if (!jobId || typeof jobId !== 'string') {
   212→            throw new Error('jobId is required and must be a string');
   213→        }
   214→
   215→        const job = await this.queue.getJob(jobId);
   216→        if (!job) {
   217→            throw new Error(`Job ${jobId} not found`);
   218→        }
   219→
   220→        await job.remove();
   221→        return { cancelled: true, jobId };
   222→    }
   223→
   224→    async clearQueue(includeActive: boolean = false) {
   225→        const counts = await this.getQueueStatus();
   226→
   227→        // Clear different job states
   228→        await this.queue.clean(0, this.QUEUE_CLEAN_LIMIT, 'completed');
   229→        await this.queue.clean(0, this.QUEUE_CLEAN_LIMIT, 'failed');
   230→        await this.queue.clean(0, this.QUEUE_CLEAN_LIMIT, 'wait');
   231→
   232→        if (includeActive) {
   233→            await this.queue.clean(0, this.QUEUE_CLEAN_LIMIT, 'active');
   234→        }
   235→
   236→        return {
   237→            clearedCompleted: counts.completed,
   238→            clearedFailed: counts.failed,
   239→            clearedWaiting: counts.waiting,
   240→            clearedActive: includeActive ? counts.active : 0
   241→        };
   242→    }
   243→
   244→    async getQueueStats() {
   245→        const waiting = await this.queue.getWaiting();
   246→        const active = await this.queue.getActive();
   247→        const completed = await this.queue.getCompleted();
   248→        const failed = await this.queue.getFailed();
   249→
   250→        return {
   251→            waiting: waiting.length,
   252→            active: active.length,
   253→            completed: completed.length,
   254→            failed: failed.length,
   255→            total: waiting.length + active.length + completed.length + failed.length,
   256→            workerThreads: 1, // Single-threaded
   257→            queueName: this.queue.name
   258→        };
   259→    }
   260→
   261→    async getWorkerStats() {
   262→        return {
   263→            threads: {
   264→                current: 1, // Single-threaded
   265→                min: 1,
   266→                max: 1
   267→            },
   268→            utilization: 0, // Not applicable for single-threaded
   269→            queueSize: 0, // Not applicable for single-threaded
   270→            completed: 0, // Not tracked in single-threaded mode
   271→            duration: 0, // Not tracked in single-threaded mode
   272→            // Additional basic stats
   273→            concurrency: 1, // Single-threaded
   274→            retryAttempts: this.RETRY_ATTEMPTS
   275→        };
   276→    }
   277→
   278→    async onModuleDestroy() {
   279→        await this.worker?.close();
   280→        await this.queueEvents?.close();
   281→        await this.queue?.close();
   282→    }
   283→}
