     2→import { TemporalEntity, TemporalEntityType } from './temporal.types';
     3→
     4→export class TemporalExtractor {
     5→    static extractEntities(text: string): TemporalEntity[] {
     6→        const results = chrono.parse(text);
     7→        const entities: TemporalEntity[] = [];
     8→
     9→        results.forEach((result) => { 
    10→            const entity = this.classifyAndBuildEntity(result, text);
    11→            if (entity) {
    12→                entities.push(entity);
    13→            }
    14→        });
    15→
    16→        return entities;
    17→    }
    18→
    19→    private static classifyAndBuildEntity(result: chrono.ParsedResult, originalText: string): TemporalEntity | null {
    20→        const type = this.classifyType(result);
    21→        if (!type) {
    22→            return null;
    23→        }
    24→
    25→        const start = result.start as any;
    26→        const end = (result.end || {}) as any;
    27→        const withScore = result as any;
    28→
    29→        return {
    30→            type,
    31→            literal: result.text,
    32→            startIndex: start.offset,
    33→            endIndex: end?.offset || start.offset + result.text.length,
    34→            confidence: withScore.score,
    35→            isoValue: this.getISOValue(result),
    36→            components: this.extractComponents(result),
    37→            metadata: { 
    38→                refDate: result.refDate,
    39→            },
    40→        };
    41→    }
    42→
    43→    private static classifyType( 
    44→        result: chrono.ParsedResult,
    45→    ): TemporalEntityType | null {
    46→        const start = result.start;
    47→        const end = result.end;
    48→
    49→        const hasYear = start.get('year') !== undefined;
    50→        const hasMonth = start.get('month') !== undefined;
    51→        const hasDay = start.get('day') !== undefined;
    52→        const hasHour = start.get('hour') !== undefined;
    53→        const hasMinute = start.get('minute') !== undefined;
    54→        const hasSecond = start.get('second') !== undefined;
    55→        const hasWeekday = start.get('weekday') !== undefined;
    56→
    57→        // if it has date and time...
    58→        if ((hasYear || hasMonth || hasDay || hasWeekday) && !(hasHour || hasMinute)) {
    59→            return 'datetime';
    60→        }
    61→
    62→        // if its only date...
    63→        if (hasYear || hasMonth || hasDay || hasWeekday) {
    64→            return 'date';
    65→        }
    66→
    67→        // if only time components...
    68→        if (hasHour || hasMinute || hasSecond) {
    69→            return 'time';
    70→        }
    71→
    72→        // if frequency...
    73→        const text = result.text.toLowerCase();
    74→        if (
    75→            text.includes('every') ||
    76→            text.includes('each') ||
    77→            text.includes('weekly') ||
    78→            text.includes('daily') ||
    79→            text.includes('monthly') ||
    80→            text.includes('yearly')
    81→        ) {
    82→            return 'frequency';
    83→        }
    84→
    85→        // if duration...
    86→        if (
    87→            text.includes('for') ||
    88→            text.includes('during') ||
    89→            text.includes('hours') ||
    90→            text.includes('days') ||
    91→            text.includes('weeks') ||
    92→            text.includes('months') ||
    93→            text.includes('years')
    94→        ) {
    95→            return 'duration';
    96→        }
    97→
    98→        return null;
    99→    }
   100→
   101→    private static extractComponents(result: chrono.ParsedResult) {
   102→        const start = result.start;
   103→        const end = result.end;
   104→
   105→        const toUndef = (v: number | null | undefined) => v === null ? undefined : v;
   106→        
   107→        return {
   108→            year: toUndef(start.get('year')),
   109→            month: toUndef(start.get('month')),
   110→            day: toUndef(start.get('day')),
   111→            hour: toUndef(start.get('hour')),
   112→            minute: toUndef(start.get('minute')),
   113→            second: toUndef(start.get('second')),
   114→            weekday: toUndef(start.get('weekday')),
   115→            // for durations
   116→            unit: this.extractTimeUnit(result.text) ?? undefined,
   117→            value: this.extractTimeValue(result.text) ?? undefined,
   118→        };
   119→    }
   120→
   121→    private static getISOValue(result: chrono.ParsedResult): string | null {
   122→        try {
   123→            const start = result.start;
   124→
   125→            // month day year ISO format
   126→            if ( 
   127→                start.get('year') !== undefined ||
   128→                start.get('month') !== undefined ||
   129→                start.get('day') !== undefined
   130→            ) {
   131→                const date = start.date();
   132→                return date.toISOString().split('T')[0]; // YYYY-MM-DD
   133→            }
   134→
   135→            // check if hour/minute
   136→            if (start.get('hour') !== undefined || start.get('minute') !== undefined) {
   137→                const date = start.date();
   138→                const hours = start.get('hour') || 0;
   139→                const minutes = start.get('minute') || 0;
   140→                const seconds = start.get('second') || 0;
   141→                return `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
   142→            }
   143→
   144→            return null;
   145→        } catch {
   146→            return null;
   147→        }
   148→    }
   149→
   150→    private static extractTimeUnit (text: string): string | null {
   151→        const lowerText = text.toLowerCase();
   152→
   153→        if (lowerText.includes('second')) return 'seconds';
   154→        if (lowerText.includes('minute')) return 'minutes';
   155→        if (lowerText.includes('hour')) return 'hours';
   156→        if (lowerText.includes('day')) return 'days';
   157→        if (lowerText.includes('week')) return 'weeks';
   158→        if (lowerText.includes('month')) return 'months';
   159→        if (lowerText.includes('year')) return 'years';
   160→
   161→        return null;
   162→    }
   163→
   164→    private static extractTimeValue(text: string): number | null {
   165→        const match = text.match(/(\d+(\.\d+)?)/);
   166→        return match ? parseInt(match[1], 10) : null;
   167→    }
   168→}

