   132→                  requestData
   133→                );
   134→                break;
   135→
   136→              case TransactionType.DATE_EXTRACTION:
   137→                this.logger.log(`Calling date extraction service for document: ${documentSourceId}`);
   138→                result = await this.dateExtractionQueueService.addDateExtractionJob(
   139→                  documentSourceId,
   140→                  undefined, // neo4jCredentials - no longer needed
   141→                  undefined, // auditId - service will create its own milestone
   142→                  false, // isRetry
   143→                  requestData,
   144→                  requestData?.options
   145→                );
   146→                break;
   147→
   148→              default:
   149→                throw new HttpException(
   150→                  `Unsupported enrichment type: ${type}`,
   151→                  HttpStatus.BAD_REQUEST
   152→                );
   153→            }
   154→
   155→            completedEnrichments.push({
   156→              type,
   157→              status: 'COMPLETED',
   158→              result
   159→            });
   160→
   161→            this.logger.log(`Successfully completed ${type} enrichment for document: ${documentSourceId}`);
   162→
   163→          } catch (error: any) {
   164→            failedEnrichments.push({
   165→              type,
   166→              status: 'FAILED',
   167→              error: error.message
   168→            });
   169→
   170→            this.logger.error(`Failed ${type} enrichment for document ${documentSourceId}: ${error.message}`, error.stack);
   171→          }
   172→        }
   173→
   174→        // Return response - the @Transactional wrapper will handle audit completion
   175→        const successfulCount = completedEnrichments.length;
   176→        const totalCount = types.length;
   177→        
