   209→    async cancelJob(jobId: string) {
   210→        // Input validation
   211→        if (!jobId || typeof jobId !== 'string') {
   212→            throw new Error('jobId is required and must be a string');
   213→        }
   214→
   215→        const job = await this.queue.getJob(jobId);
   216→        if (!job) {
   217→            throw new Error(`Job ${jobId} not found`);
   218→        }
   219→
   220→        await job.remove();
   221→        return { cancelled: true, jobId };
   222→    }
