   249→
   250→        return {
   251→            waiting: waiting.length,
   252→            active: active.length,
   253→            completed: completed.length,
   254→            failed: failed.length,
   255→            total: waiting.length + active.length + completed.length + failed.length,
   256→            workerThreads: 1, // Single-threaded
   257→            queueName: this.queue.name
   258→        };
   259→    }
