    94→      this.logger.log(
    95→        `User ${req.user.username} (ID: ${req.user.sub}) triggering enrichment for document ${documentSourceId} ` +
    96→        `with types: ${types.join(', ')} using transaction: ${auditId}`
    97→      );
    98→
    99→      // Use AsyncTransactionHelper for clean async execution
   100→      return this.asyncHelper.executeAsync(auditId, async () => {
   101→        const completedEnrichments: any[] = [];
   102→        const failedEnrichments: any[] = [];
   103→
   104→        // Process each enrichment type - services will create their own milestones  
   105→        for (const type of types) {
   106→          this.logger.log(`Processing enrichment type: ${type} for document: ${documentSourceId}`);
   107→
   108→          try {
   109→            // Call appropriate enrichment service - they handle their own milestones
   110→            let result: any;
   111→            switch (type) {
   112→              case TransactionType.EMBEDDING:
   113→                this.logger.log(`Calling embedding service for document: ${documentSourceId}`);
   114→                result = await this.embeddingQueueService.addEmbeddingJob(
   115→                  documentSourceId,
   116→                  requestData?.batchSize,
   117→                  undefined, // neo4jCredentials - no longer needed
   118→                  undefined, // auditId - service will create its own milestone
   119→                  false, // isRetry
   120→                  requestData
   121→                );
   122→                break;
   123→
   124→              case TransactionType.GLOSSARY_ADD:
   125→                this.logger.log(`Calling glossary service for document: ${documentSourceId}`);
   126→                result = await this.glossaryQueueService.addGlossaryJob(
   127→                  documentSourceId,
   128→                  'GLOSSARY_ADD',
   129→                  undefined, // neo4jCredentials - no longer needed
   130→                  undefined, // auditId - service will create its own milestone
   131→                  false, // isRetry
   132→                  requestData
   133→                );
   134→                break;
   135→
   136→              case TransactionType.DATE_EXTRACTION:
   137→                this.logger.log(`Calling date extraction service for document: ${documentSourceId}`);
   138→                result = await this.dateExtractionQueueService.addDateExtractionJob(
   139→                  documentSourceId,
   140→                  undefined, // neo4jCredentials - no longer needed
   141→                  undefined, // auditId - service will create its own milestone
   142→                  false, // isRetry
   143→                  requestData,
   144→                  requestData?.options
   145→                );
   146→                break;
   147→
   148→              default:
   149→                throw new HttpException(
   150→                  `Unsupported enrichment type: ${type}`,
   151→                  HttpStatus.BAD_REQUEST
   152→                );
   153→            }
   154→
   155→            completedEnrichments.push({
   156→              type,
   157→              status: 'COMPLETED',
   158→              result
   159→            });
   160→
   161→            this.logger.log(`Successfully completed ${type} enrichment for document: ${documentSourceId}`);
   162→
   163→          } catch (error: any) {
   164→            failedEnrichments.push({
   165→              type,
   166→              status: 'FAILED',
   167→              error: error.message
   168→            });
   169→
   170→            this.logger.error(`Failed ${type} enrichment for document ${documentSourceId}: ${error.message}`, error.stack);
   171→          }
   172→        }
   173→
   174→        // Return response - the @Transactional wrapper will handle audit completion
   175→        const successfulCount = completedEnrichments.length;
   176→        const totalCount = types.length;
   177→        
   178→        return {
   179→          auditId, // Using REQUEST audit ID for backwards compatibility
   180→          status: successfulCount === totalCount ? 'COMPLETED' :
   181→            successfulCount > 0 ? 'PARTIAL_SUCCESS' : 'FAILED',
   182→          documentSourceId: documentSourceId,
   183→          createdAt: new Date(),
   184→          message: `${successfulCount}/${totalCount} enrichment(s) completed successfully`,
   185→          results: [...completedEnrichments, ...failedEnrichments]
   186→        } as EnrichmentResponseDto;
   187→      });
   188→
   189→    } catch (error: any) {
   190→      this.logger.error(`Error triggering enrichment job: ${error.message}`, error.stack || '');
   191→      throw new HttpException(
   192→        error.message || 'Failed to trigger enrichment job',
   193→        error.status || HttpStatus.INTERNAL_SERVER_ERROR
   194→      );
   195→    }
   196→  }
